PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?person ?personLabel WHERE {
  {
    ?person wdt:P39 wd:Q6256 ; wdt:P106 wd:Q55630100 .
  } UNION {
    ?person wdt:P39 wd:Q6255 ; wdt:P106 wd:Q55630100 .
  } UNION {
    ?person wdt:P39 wd:Q6256 ; wdt:P22 ?father .
    ?father wdt:P106 wd:Q55630100 .
  } UNION {
    ?person wdt:P39 wd:Q6255 ; wdt:P22 ?father .
    ?father wdt:P106 wd:Q55630100 .
  }
  OPTIONAL {
    ?person rdfs:label ?personLabel .
    FILTER(LANG(?personLabel) = "en")
  }
}

